// Helper functions for modal
function showReportsModal(rowData) {
  const overlay2 = document.getElementById('modal-overlay2');
  const modalBody2 = document.getElementById('modal-body2');

  modalBody2.innerHTML = `
    &lt;h2&gt;${rowData.Title}&lt;/h2&gt;
    &lt;div style="margin-bottom: 1rem; font-weight: 500;"&gt;${rowData.Authors || ''} (${rowData.Date || ''})&lt;/div&gt;

    &lt;div style="margin-bottom: 1rem;"&gt;&lt;strong&gt;Publication type:&lt;/strong&gt; ${rowData.Type || 'N/A'}&lt;/div&gt;
    &lt;div style="margin-bottom: 1rem;"&gt;&lt;strong&gt;Topic/theme:&lt;/strong&gt; ${rowData.Topics || 'N/A'}&lt;/div&gt;
    &lt;div style="margin-bottom: 1rem;"&gt;&lt;strong&gt;Format / Status:&lt;/strong&gt; ${rowData.Report_Format || ''} — ${rowData.Publication_Status || ''}&lt;/div&gt;

    &lt;div style="background: #f5f5f5; padding: 1rem; border-radius: 4px; margin-bottom: 1rem;"&gt;${rowData.Description || ''}&lt;/div&gt;

    &lt;div&gt;
      &lt;a href="${rowData.URL}" target="_blank" class="btn btn-quarto"&gt;View Report&lt;/a&gt;
    &lt;/div&gt;
  `;

  overlay2.style.display = 'flex';
}

function hideReportsModal() {
  const overlay2 = document.getElementById('modal-overlay2');
  if (overlay2) overlay2.style.display = 'none';
}

// Set up close handlers after modal is rendered
{
  setTimeout(() =&gt; {
    const closeBtn2 = document.getElementById('modal-close2');
    const overlay2 = document.getElementById('modal-overlay2');

    if (closeBtn2) {
      closeBtn2.addEventListener('click', hideReportsModal);
    }

    if (overlay2) {
      overlay2.addEventListener('click', (e) =&gt; {
        if (e.target.id === 'modal-overlay2') hideReportsModal();
      });
    }
  }, 100);
}






























viewof reports_table = Inputs.table(filtered_reports, {
  columns: ["Title", "Authors", "Date", "Type", "Topics", "Link"], 
  sort: false,
  format: {
    Link: (testValue, row_index) =&gt; {
      const div = document.createElement('div');
      div.innerHTML = testValue;

      const button = div.querySelector('button');
      if (button) {
        button.addEventListener('click', () =&gt; {
          const rowData = filtered_reports[row_index];
          showReportsModal(rowData);
        });
      }

      return div;
    },
    Description_snippet: Test =&gt; {
      const div = document.createElement('div');
      div.innerHTML = Test;
      return div;
    }
  },
  rows: 20
})








